CREATE OR REPLACE FUNCTION fpb_get_member_status_code (as_memno char) RETURNS varchar AS $body$
DECLARE

ls_member_status_code char;

BEGIN
  select	member_status_code
  into STRICT    ls_member_status_code
  from		sc_mem_m_membership_registered
  where	  trim(both membership_no) = as_memno
;
  RETURN ls_member_status_code;
  exception when others then return ' ';
END;
$body$
